"""
MKT Original Commentary — 1 Corinthians chapters 5-8
Run: python3 scripts/zc-original-1corinthians-5-8.py

Source data used:
- data/interlinear/1corinthians.json
- data/translation/glossary-greek.json (porneia, sarx, pneuma, zymē, malakoi, arsenokoitai, gnōsis, agapē)
- data/translation/notes/1corinthians.json (dispute flags for 5:5, 6:9, 6:11, 7:7, 7:14, 7:39, 8:1)
- data/translation/draft/mediating/1corinthians.json

Key decisions in this range:
- sarx (5:5) rendered 'sinful nature' in MKT but Greek sense is the whole embodied self under sin's
  domination — not merely an inner corrupt impulse but the whole person as mortal/corruptible
- malakoi/arsenokoitai (6:9): these two terms describe passive and active same-sex roles;
  arsenokoitai is a Pauline coinage from Lev 18:22/20:13 LXX (arsenos koitē = male bed)
- 'I have the right to do anything' (6:12) is a Corinthian slogan Paul quotes twice and twice
  reframes — not Paul's statement; marked accordingly
- kairos synestalmenos (7:29) = contracted/compressed, not merely 'short'; the metaphor is
  of a rolled-up sail or gathered garment, implying urgency
- 7:21 mallon chrēsai: the ambiguous command to take/use freedom if available; MKT renders 'take
  the opportunity' which favors manumission over remaining in slavery
- No straight double-quote characters inside value strings; typographic quotes used throughout
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "5": {
    "1": '<p><strong>porneia</strong> (<em>porneia</em>) is Paul\'s broad term for sexual immorality, but the clause specifies a named species: a man has his father\'s wife (<em>tēn gynaika tou patros echein</em>). This is not adultery in the technical sense (the father may be dead or divorced) but incest-adjacent — a step-relationship prohibited explicitly in Lev 18:8 and Deut 22:30, with the death penalty at Lev 20:11. Paul\'s rhetorical <em>holos akouetai</em> (it is actually reported) signals the report has reached him in Ephesus and he treats it as established fact, not rumor.</p>',
    "2": '<p><strong>pephysiōmenoi este</strong> (<em>pephysiōmenoi este</em>) — perfect passive: you are in a state of being puffed up. The same root (<em>physioō</em>) recurs in 4:6, 4:18, 4:19, 5:2, 8:1, 13:4 — it is one of Paul\'s recurring diagnoses of the Corinthian community\'s fundamental problem. <strong>penthēsēte</strong> (mourn) — the mourning vocabulary is that of lament for the dead or for communal sin (Jas 4:9; 2 Cor 12:21), not merely sorrow. <strong>exarthē</strong> (put out/removed) — aorist passive imperative: an action that should have already happened.</p>',
    "3": '<p><strong>apōn tō sōmati, parōn de tō pneumati</strong> (<em>apōn … parōn</em>): absent in body, present in spirit. Paul asserts a real apostolic presence through the Spirit that enables genuine judicial action at a distance. <strong>kekrika</strong> (I have already passed judgment) — perfect indicative: the verdict is rendered, not deliberated. Paul\'s authority is not contingent on physical presence; his judgment in this matter precedes the assembly\'s action.</p>',
    "4": '<p><strong>en tō onomati tou Kyriou Iēsou</strong> (in the name of the Lord Jesus) — the assembly is constituted by this invocation; the name makes Christ present. <strong>synachthentōn hymōn</strong> (when you are assembled) — the gathered community, not the individual, is the locus of this disciplinary action. The <em>dynamis</em> (power) of the Lord Jesus mentioned here is the same power invoked at baptism and exorcism — the action is charismatic, not merely procedural.</p>',
    "5": '<p><strong>paradounai ton toiouton tō Satana</strong> (hand this man over to Satan): a formal judicial act of excommunication. Expulsion from the covenant community was understood in Second Temple Judaism to place one outside divine protection — in the domain where the Adversary operates (cf. Job 1–2; Luke 22:31). <strong>olethros tēs sarkos</strong> — the destruction of the <em>sarx</em>. The translation note flags this as contested: <em>sarx</em> here is not merely the physical body but the whole person as constituted under sin\'s power — the corruptible, mortal, sin-dominated self. The destruction of the <em>sarx</em> through suffering and exclusion serves the salvation of the <em>pneuma</em> — the person\'s restored spiritual standing before God on the Day of the Lord. This is corrective, not punitive in a final sense.</p>',
    "6": '<p><strong>to kauchēma hymōn</strong> (your boasting) — not boasting about this specific case but the community\'s general self-congratulation (4:7: what do you have that you did not receive?). <strong>zymē</strong> (<em>zymē</em>, leaven): Paul deploys the Passover preparation metaphor. In Jewish practice, before Passover all leaven (<em>chametz</em>) was removed from the house — a thorough, house-by-house search. A small amount of yeast permeates the entire batch (<em>holon to phyrama</em>) — the metaphor applies directly: one unaddressed sin corrupts the whole community\'s moral integrity.</p>',
    "7": '<p><strong>ekkatharate tēn palaian zymēn</strong> (purge out the old leaven) — aorist imperative, urgent action. <strong>azymoi este</strong> (you are unleavened) — present indicative: the indicative precedes the imperative; you are already what you are called to become. <strong>to pascha hēmōn etythē Christos</strong> (Christ our Passover lamb has been sacrificed) — Paul\'s explicit Passover typology: Christ is the <em>pascha</em>, the Passover sacrifice. The aorist <em>etythē</em> (was slaughtered/sacrificed) uses the technical Passover slaughter term. This is not an analogy but a typological fulfillment claim: the Exodus Passover was always moving toward this event.</p>',
    "8": '<p><strong>heortazōmen</strong> (let us keep the festival) — present subjunctive of exhortation: the whole Christian life is a Passover festival begun by Christ\'s sacrifice. <strong>palaia zymē</strong> (old leaven) = the pre-conversion life characterized by <em>kakias kai ponērias</em> (malice and wickedness). <strong>azymois eilikrinias kai alētheias</strong> (unleavened bread of sincerity and truth) — the two nouns in apposition interpret what genuine post-Passover life looks like: <em>eilikrineia</em> (purity, unmixed quality, from sun-testing for impurities) and <em>alētheia</em> (truth, reality as opposed to pretense). The festival metaphor reframes ethics as cultic participation.</p>',
    "9": '<p><strong>egrapsa hymin</strong> (I wrote to you) — aorist, referring to a prior letter now lost. This is the earliest evidence that Paul wrote to Corinth before 1 Corinthians — what some scholars call the Vorbrief. Paul corrects a misreading of that letter: they apparently interpreted his instruction about not associating with the sexually immoral as applying to outsiders, which he now clarifies was absurd.</p>',
    "10": '<p><strong>epei ara</strong> (since otherwise) — a reductio ad absurdum: if the prohibition applied to all immoral people in the world, leaving the world would be the only option. Paul\'s instruction was never a call to social withdrawal but to internal community discipline. The list — sexually immoral, greedy, swindlers, idolaters — is the standard Pauline vice catalogue applied to outsiders about whom he makes no disciplinary claim.</p>',
    "11": '<p><strong>nun de egrapsa hymin</strong> (but now I write to you) — the contrast with v. 9\'s prior letter is explicit: this letter clarifies. The clause <em>adelphos onomazomenos</em> (one who bears the name brother) is key — the disciplinary authority extends only within the named community. <strong>mēde synesthiein</strong> (not even to eat with such a person) — table fellowship in the ancient world was covenant-expression; refusing the shared meal is the practical enactment of exclusion from the covenant community.</p>',
    "12": '<p><strong>ti gar moi tous exō krinein</strong> (what business is it of mine to judge those outside?) — rhetorical question. Paul draws a firm epistemological boundary: the church has no judicial authority over those outside it. God will judge them (<em>tous de exō ho theos krinei</em>, v. 13). But the inside is another matter: <em>tous de esō hymeis krinete</em> (those inside you judge). The community\'s disciplinary authority is internal and self-referential.</p>',
    "13": '<p><strong>tous de exō ho theos krinei</strong> (God will judge those outside) — Paul attributes final judgment of outsiders to God alone, not to the community. <strong>exarate ton ponēron ex hymōn autōn</strong> — direct quotation of Deut 17:7 (also 19:19; 21:21; 22:21 — the refrain of the Deuteronomic purity-law): expel the wicked person from among you. Paul applies Torah\'s community-boundary law to the church. The aorist imperative is decisive and urgent.</p>'
  },
  "6": {
    "1": '<p><strong>tolmai</strong> (dare) — the verb implies moral effrontery, not merely courage. The act requires a kind of audacity. <strong>epi tōn adikōn</strong> (before the unrighteous) — <em>adikoi</em> here is not a generic moral epithet but a technical category: those outside the covenant community, who by definition lack the standard of righteousness that would qualify them to adjudicate covenant disputes. <strong>epi tōn hagiōn</strong> (before the saints) — the church as the community of the holy, the proper forum for internal disputes.</p>',
    "2": '<p><strong>ouk oidate hoti hoi hagioi ton kosmon krienousi</strong> (do you not know that the saints will judge the world?) — the <em>ouk oidate</em> (do you not know) formula recurs eight times in 1 Corinthians (6:2, 3, 9, 15, 16, 19; 5:6; 3:16) — Paul appeals to a body of shared knowledge the Corinthians already possess but are not applying. The saints judging the world is a Second Temple expectation (Dan 7:22; Wis 3:7-8; 1 En. 1:9): the redeemed community participates in eschatological judgment. If they will judge the cosmos, they are surely competent for petty disputes (<em>kritēria elachistōn</em>, smallest cases).</p>',
    "3": '<p><strong>angelous krienoumen</strong> (we will judge angels) — not a speculative assertion but a shared eschatological belief. Paul assumes his readers accept this; he appeals to it to shame their failure at the lower task of judging this-life matters (<em>biōtika</em>, things of this life).</p>',
    "4": '<p><strong>exouthenēmenous en tē ekklēsia</strong> (those who are held in contempt in the church) — either ironic (Paul is sarcastically suggesting they are appointing the scorned as judges) or a genuine re-evaluation: those the world scorns are qualified by their standing in the community. The sentence is interrogative or imperatival — scholars debate whether Paul is mocking their behavior or directing it. Either reading surfaces the absurdity of taking Christian disputes before pagan courts.</p>',
    "5": '<p><strong>pros entropēn</strong> (to shame you) — Paul invokes the honor-shame framework directly. <strong>sophos</strong> (wise person): the vocabulary of wisdom picks up Paul\'s sustained argument from chs. 1–4. The Corinthians pride themselves on wisdom (<em>sophia</em>); Paul now says their legal behavior proves there is not one person wise enough to resolve a dispute between siblings in Christ. This is a deliberate inversion of their self-image.</p>',
    "6": '<p><strong>adelphos meta adelphou krinetai</strong> (brother goes to court against brother) — the repetition of <em>adelphos</em> (brother) intensifies the contradiction: the covenant-bond of siblinghood is violated by the very act of external litigation. <strong>kai touto epi apistoōn</strong> (and this before unbelievers) — the public visibility makes it a witness-failure, not only a community-failure.</p>',
    "7": '<p><strong>hēttēma</strong> (defeat, loss): a legal-commercial term; already, before the verdict is rendered, the very existence of the lawsuit is a defeat. The Stoic/Cynic philosophical tradition valued being wronged without retaliation as the mark of the sage; Paul invokes this expectation — <em>ouchi mallon adikeisthe? ouchi mallon apostereisthe?</em> (why not rather be wronged? why not rather be cheated?) — but grounds it not in philosophical virtue but in community honor and eschatological perspective.</p>',
    "8": '<p><strong>alla hymeis adikeite kai apostereite</strong> (instead, you yourselves do wrong and cheat) — the reversal: the Corinthians are not merely failing to endure wrong; they are actively perpetrating it against brothers and sisters. <em>Apostereō</em> (defraud) is the same verb used in 7:5 for depriving a spouse — here it is economic exploitation within the community.</p>',
    "9": '<p><strong>adikoi</strong> (the unrighteous) connects to v. 1\'s <em>epi tōn adikōn</em>: Paul now defines the category from the inside. The vice catalogue that follows is one of Paul\'s four (others: Rom 1:29-31; Gal 5:19-21; Col 3:5-8). <strong>malakoi</strong> (<em>malakoi</em>, lit. soft ones): used in secular Greek for the passive partner in male same-sex acts; also for men who adopted feminine roles. <strong>arsenokoitai</strong> (<em>arsenokoitai</em>): a Pauline coinage (earliest known use); formed from <em>arsēn</em> (male) + <em>koitē</em> (bed/sexual intercourse) — the compound reflects the LXX of Lev 18:22 (<em>meta arsenos koitēn gynaikos</em>) and 20:13 (<em>hos an koimēthē meta arsenos koitēn gynaikos</em>). Paul constructed the term from the Torah text that prohibits the act; it denotes the active male partner.</p>',
    "10": '<p>The vice list concludes with <em>kleptai</em> (thieves), <em>pleonektai</em> (greedy/covetous), <em>methysoi</em> (drunkards), <em>loidoroi</em> (slanderers), <em>harpages</em> (swindlers). None of these, Paul says, will inherit the kingdom (<em>basileian Theou ou klēronomēsousin</em>). The list is not hierarchical — no single vice is worse than others. All represent modes of living oriented away from God and toward self-assertion.</p>',
    "11": '<p><strong>kai tauta tines ēte</strong> (and some of you were these things) — perfect past: the list of vv. 9-10 described some of the Corinthians\' pre-conversion lives. The aorist passive triad that follows is the hinge of the sentence: <strong>apelousasthe</strong> (you were washed — baptism), <strong>hēgiasthēte</strong> (you were sanctified — set apart/made holy), <strong>edikaiōthēte</strong> (you were justified — declared righteous before God). All three are aorist passives: God\'s action, not the believer\'s. The agency is double: <em>en tō onomati tou Kyriou Iēsou Christou</em> (in the name of the Lord Jesus Christ) and <em>en tō pneumati tou Theou hēmōn</em> (by the Spirit of our God). Identity transformation through divine action is the ground for the ethical demand.</p>',
    "12": '<p><strong>panta moi exestin</strong> (I have the right to do anything) — twice quoted, twice qualified. This is a Corinthian slogan, not Paul\'s own assertion. The community apparently argued that Christian freedom (grace, not law) entails no moral constraints. Paul does not deny the slogan but applies two limits: <em>all ou panta sympherei</em> (not everything is beneficial/profitable) — the communal frame; and <em>all ouk egō exousiasthēsomai hypo tinos</em> (I will not be mastered by anything) — the personal frame. The word <em>exousia</em> (authority/right) recurs in different grammatical forms: freedom is not the abolition of authority but its proper exercise.</p>',
    "13": '<p><strong>ta brōmata tē koilia kai hē koilia tois brōmasin</strong> (food for the stomach and the stomach for food) — another Corinthian slogan Paul quotes before demolishing. The argument: just as digestion is morally neutral, so sex is morally neutral. Paul\'s counter is christological: the body is <em>ou tē porneia alla tō Kyriō</em> (not for sexual immorality but for the Lord), and the Lord is for the body. This moves the body out of the category of morally neutral biological function and into the category of Christ\'s own — a property relationship that reframes all bodily ethics.</p>',
    "14": '<p><strong>ho de Theos kai ton Kyrion ēgeiren kai hēmas exegerei</strong> (by his power God raised the Lord from the dead, and he will raise us also) — the resurrection of Christ establishes the body\'s eschatological dignity. If the body participates in resurrection, it cannot be treated as a morally neutral organism. The future <em>exegerei</em> (will raise) is the ground of the present ethics: the body that will be raised is the body that is now joined to Christ.</p>',
    "15": '<p><strong>ouk oidate hoti ta sōmata hymōn melē Christou estin</strong> (do you not know that your bodies are members of Christ?) — <em>melē</em> (members, limbs) is the body-of-Christ vocabulary: the individual body is a member of Christ\'s own body. <strong>aras oun ta melē tou Christou poiēsō pornēs melē</strong> (shall I then take the members of Christ and make them members of a prostitute?) — the question is rhetorical and its answer (<em>mē genoito</em>, never!) is Paul\'s strongest negative formula, used only when the option is theologically impossible.</p>',
    "16": '<p><strong>kollōmenos tē pornē hen sōma estin</strong> (the one who unites himself with a prostitute is one body with her) — Paul applies the one-flesh principle from Gen 2:24 (<em>esontai hoi dyo eis sarka mian</em>) to the prostitute encounter. The sexual union creates a real bodily bond (<em>hen sōma</em>), not a merely physical exchange. The argument depends on the body\'s non-neutrality: sex does something metaphysically, not just biologically.</p>',
    "17": '<p><strong>ho de kollōmenos tō Kyriō hen pneuma estin</strong> (but the one who is united to the Lord is one spirit with him) — the parallelism with v. 16 is deliberate. Both relationships are characterized by union (<em>kollaō</em>, cleave/join); both produce a oneness; but the union with the Lord is <em>pneumatic</em> (spiritual), not merely somatic. This does not spiritualize the body away — the body is the site of both unions — but establishes the qualitative difference between the two allegiances.</p>',
    "18": '<p><strong>pheugete tēn porneian</strong> (flee from sexual immorality) — aorist imperative of flight, the same word used of Joseph fleeing Potiphar\'s wife (LXX Gen 39:12). The call to flee rather than resist is significant: <em>porneia</em> is not an enemy to engage but a snare to escape. <strong>pan hamartēma ho ean poiēsē anthrōpos ektos tou sōmatos estin</strong> — every sin a person commits is outside the body; but sexual immorality is <em>eis to idion sōma</em> (against one\'s own body). The precise meaning of this uniqueness is debated, but Paul\'s point is that bodily sexual sin constitutes a distinctive violation of the body\'s integrity as the locus of Christ-union and Spirit-indwelling.</p>',
    "20": '<p><strong>ēgorasthēte gar timēs</strong> (you were bought at a price) — the commercial-legal metaphor: the believer has been purchased from their prior owner (sin, death, the powers). <em>Agorazō</em> is the marketplace verb for buying; used of slave redemption. The implication is a transfer of ownership: they are not their own (<em>ouk este heautōn</em>). <strong>doxasate dē ton Theon en tō sōmati hymōn</strong> (therefore glorify God with your body) — the imperativis grounded in the indicative: because you were purchased, honor God with the body that belongs to him. The body is the site of glorification, not an obstacle to it.</p>'
  },
  "7": {
    "1": '<p><strong>peri de hōn egrapsate</strong> (now about the matters you wrote about) — the first of seven such formula-openings in 1 Corinthians (7:1; 7:25; 8:1; 12:1; 16:1; 16:12), signaling Paul\'s shift to answering the Corinthians\' own questions. <strong>kalon anthrōpō gynaikos mē haptesthai</strong> (it is good for a man not to touch a woman) — another Corinthian slogan Paul quotes. <em>Haptomai</em> (touch) is a standard euphemism for sexual intercourse (cf. Gen 20:6 LXX). Paul neither endorses nor condemns the slogan — he immediately qualifies it with the concessive <em>dia de tas porneias</em> (but because of sexual immorality cases…).</p>',
    "2": '<p><strong>dia de tas porneias</strong> (but because of sexual immorality cases) — the plural <em>porneias</em> implies recurring instances in the community. <strong>heautou gynaika</strong>/<strong>idion andra</strong> (his own wife / her own husband) — the reciprocal possession language is striking: each has their own spouse; neither spouse is communal property. This grammatical reciprocity anticipates the full mutual-authority language of v. 4.</p>',
    "3": '<p><strong>tēn opheilomenēn eunonian apodidotō</strong> (let him fulfill the conjugal duty) — <em>opheilomenēn</em> (owed, due): marriage creates a debt structure; each spouse owes the other conjugal attention. <em>Apodidōmi</em> (give back, render) is the debt-payment verb — not gift language but obligation language. Paul frames marital sexual relations as a mutual duty, not a concession. This is among Paul\'s most egalitarian statements in a context where husbands routinely denied their wives access to their bodies.</p>',
    "4": '<p><strong>hē gynē tou idiou sōmatos ouk exousiazei alla ho anēr; homoiōs de kai ho anēr</strong> — the mutual <em>exousiazō</em> (has authority over) is remarkable: each spouse has authority over the other\'s body, not merely their own. The statement is symmetrical (<em>homoiōs de kai</em>) — husband and wife are placed on identical terms regarding conjugal authority. In the context of Greco-Roman household ethics, where the wife was subordinate in all matters, this mutual claim on bodily access is counter-cultural.</p>',
    "5": '<p><strong>mē apostereite allēlous</strong> (do not deprive each other) — <em>apostereō</em> (defraud, deprive) appears also at 6:8; here in the sexual context of mutual conjugal obligation. <strong>ei mē an ek symphōnou</strong> (except by mutual agreement) — the exception clause: abstinence is legitimate only when <em>both</em> agree. <strong>pros ton kairon</strong> (for a season) — temporary, bounded. <strong>scholasēte tē proseuchē</strong> (devote yourselves to prayer) — the purpose: ascetic abstinence for focused prayer, a recognized Jewish practice (cf. Joel 2:16; LXX 1 Sam 21:5). <strong>akrasia</strong> (lack of self-control) — Paul acknowledges desire as a real and potentially dangerous force.</p>',
    "6": '<p><strong>touto de legō kata syngnōmēn, ou kat\' epitagēn</strong> (I say this as a concession, not as a command) — Paul carefully distinguishes: what he says about the concession for abstinence (v. 5) is a <em>syngnōmē</em> (concession, permission), not a <em>epitagē</em> (divine command). This is an important hermeneutical marker: he is making a pastoral accommodation, not a theological absolute.</p>',
    "7": '<p><strong>thelō de pantas anthrōpous einai hōs kai emauton</strong> (I wish that all people were like me) — Paul situates himself as a model of celibate life. The translation note flags the dispute: Paul\'s <em>charisma</em> (spiritual gift, v. 7b) for celibacy is a genuine gift (<em>charisma</em> is the standard Pauline term for Spirit-given capacity, cf. ch. 12), not a universal calling. <strong>hekastos idion charisma echei ek Theou, ho men houtōs, ho de houtōs</strong> (each has their own gift from God, one of one kind and another of another) — both marriage and celibacy are <em>charismata</em>; neither is superior in the sense that both are divine gifts.</p>',
    "8": '<p><strong>tois agamois kai tais chērais</strong> (to the unmarried and to widows) — <em>agamos</em> (unmarried) is Paul\'s coinage for those who have never been married or who are no longer married; it appears only in this chapter. The recommendation <em>meinai hōs kagō</em> (to remain as I am) implies Paul himself is unmarried at this point — widowed (if previously married) or never married.</p>',
    "9": '<p><strong>ei de ouk enkrateuontai, gamēsatōsan</strong> (but if they do not have self-control, let them marry) — <em>enkrateuomai</em> (have self-control, contain oneself) is the virtue of self-mastery prized in both Stoic ethics and Jewish piety. <strong>kreitton gar estin gamēsai ē pyrousthai</strong> (it is better to marry than to burn with passion) — <em>pyrousthai</em> (to burn, be inflamed): the metaphor of sexual desire as fire. Paul does not frame marriage as a necessary evil but as the appropriate remedy — <em>kreitton</em> (better), a comparative that implies both options have merit.</p>',
    "10": '<p><strong>tois de gegamēkosi parangellō, ouk egō alla ho Kyrios</strong> (to the married I give this instruction — not from me but from the Lord) — Paul distinguishes sharply between his own judgment and a direct command from the Lord Jesus. Here he has an explicit saying of Jesus (cf. Mark 10:11-12; Matt 5:32): the wife (<em>gynaika</em>) must not separate (<em>chōristhēnai</em>) from her husband. <em>Parangellō</em> (command) is the authoritative instructional verb, stronger than <em>legō</em> (say) or <em>gnōmēn didōmi</em> (give my opinion, v. 25).</p>',
    "11": '<p><strong>ean de kai chōristhē</strong> (but if she does separate) — Paul acknowledges that the separation may happen even against the command. His instruction in that case: remain unmarried (<em>agamos menetō</em>) or be reconciled (<em>katallagētō</em>) to her husband. <em>Katallagē</em> is Paul\'s reconciliation vocabulary (2 Cor 5:18-20; Rom 5:11) — here applied to marital breakdown. The possibility of reconciliation is kept open; permanent new remarriage is not authorized while the husband lives.</p>',
    "12": '<p><strong>tois de loipois legō egō, ouch ho Kyrios</strong> (to the others I say — I, not the Lord) — Paul has no recorded saying of Jesus for this situation (mixed marriage). He explicitly flags this: his instruction carries apostolic authority but not a dominical command. <em>Legō egō</em> (I say, I) — the emphatic pronoun marks his own authority, distinct from the Lord\'s. The situation he addresses is post-conversion mixed marriage, not a believer marrying an unbeliever.</p>',
    "13": '<p><strong>kai gynē ētis echei andra aiston</strong> (and a woman who has an unbelieving husband) — the symmetry: the situation applies equally to believing wife with unbelieving husband. <strong>mē aphietō ton andra</strong> (she should not divorce her husband) — the verb <em>aphiēmi</em> is the standard Greek divorce term. Paul\'s instruction is the same in both directions: do not initiate divorce from an unbelieving but consenting spouse.</p>',
    "14": '<p><strong>hēgiastai gar ho anēr ho apistos en tē gynaiki</strong> (the unbelieving husband is made holy through his believing wife) — <em>hēgiastai</em> is perfect passive: a settled state of being-made-holy. This does not mean the unbelieving spouse is saved but that the household is brought within the sphere of sanctification by the presence of a believing partner. The translation note flags the dispute. <em>Hagia</em> (holy) applied to the children of such a union — the household participates in holiness by association.</p>',
    "15": '<p><strong>ei de ho apistos chōrizetai, chōrizesthō</strong> (but if the unbelieving partner separates, let them go) — the exception: if the unbeliever initiates departure, the believer is not obligated to prevent it. <strong>ou dedoulōtai ho adelphos ē hē adelphē en tois toioutois</strong> (a brother or sister is not enslaved in such cases) — <em>dedoulōtai</em> (enslaved, bound) picks up the slavery metaphor that runs through ch. 7: marriage creates a binding, but the unbeliever\'s departure releases the binding. <strong>en eirēnē keklēken hēmas ho Theos</strong> (God has called us to peace) — the calling to peace overrides the compulsion to preserve a marriage that the unbeliever has already abandoned.</p>',
    "16": '<p><strong>ti gar oidas, gynai, ei ton andra sōseis</strong> (for how do you know, wife, whether you will save your husband?) — the rhetorical question is a pastoral caution: do not stay in a destructive marriage on the grounds of the missionary hope, since that outcome is uncertain. The verse has been read optimistically (you might save them — so stay) or pessimistically (you might not save them — so don\'t chain yourself to that hope). The latter reading fits the context better: Paul is warning against treating the mixed marriage as a guaranteed mission field.</p>',
    "17": '<p><strong>hōs ekklēsen ho Theos hekaston, houtōs peripatatō</strong> (let each person live as God has assigned them, as the Lord has called them) — the calling principle: the condition in which God\'s call found you is not a problem to be escaped but a vocation to be lived. <em>Keklēken</em> (has called) is the perfect: the call was made and remains in force. <strong>kai houtōs en tais ekklesiais pasais diatassō</strong> (this is my rule in all the churches) — Paul claims this as a universal apostolic teaching, not a local accommodation.</p>',
    "18": '<p><strong>en peritomē eklēthē tis</strong> (was someone called while circumcised?) — the calling principle applied to Jewish identity. <em>Epispasthō</em> (let him not remove marks of circumcision) — epispasm: a surgical procedure used by some Jews to restore the appearance of foreskin, documented in 1 Macc 1:15. Paul forbids it: the marker of the prior covenant-identity need not be hidden. Similarly, the uncircumcised should not seek circumcision.</p>',
    "19": '<p><strong>hē peritomē ouden estin kai hē akrobystia ouden estin, alla tērēsis entolōn Theou</strong> (circumcision is nothing and uncircumcision is nothing; keeping God\'s commands is what matters) — the radical relativization of the covenant marker: neither circumcision nor its absence has intrinsic value. What matters is <em>entolōn tērēsis</em> (keeping God\'s commands). This is not antinomian (Paul upholds commands) but anti-ethnic-marker: ethnic-covenant status does not constitute righteousness.</p>',
    "20": '<p><strong>hekastos en tē klēsei hē eklēthē, en tautē menetō</strong> (let each person remain in the situation they were in when God called them) — the governing principle of vv. 17-24 stated plainly. <em>Klēsis</em> (calling, vocation): Paul may be using this in its sociological sense (condition: slave, free, circumcised, uncircumcised) or theological sense (divine call into Christ). Both are probably in view: God\'s call finds you in a particular condition and makes that condition the site of your vocation.</p>',
    "21": '<p><strong>doulos eklēthēs; mē soi meletō</strong> (were you a slave when called? do not let it trouble you) — the advice is: your slave status does not impede your standing before God. <strong>all\' ei kai dynasthai eleuthos genesthai, mallon chrēsai</strong> (but if you are indeed able to gain your freedom, take the opportunity) — the contested phrase. <em>Mallon chrēsai</em> (use/avail yourself more rather): grammatically ambiguous — take the freedom, or use your slave status (for the Lord). The majority of scholars now favor the manumission reading: if freedom is available, take it. <em>Dynasthai</em> (be able) implies an actual offer, not a hypothetical.</p>',
    "22": '<p><strong>ho gar en Kyriō klētheis doulos apeleutheros Kyriou estin</strong> (the one who was a slave when called in the Lord is the Lord\'s freed person) — Paul applies the manumission metaphor to spiritual status: the slave who belongs to Christ has been set free (<em>apeleutheros</em>, freed person) in the most important sense. <strong>homoiōs ho eleutheros klētheis doulos Christou estin</strong> (similarly, the free person who was called is Christ\'s slave) — the free person, by coming to Christ, becomes a slave of Christ. The social asymmetry is inverted: freedom in Christ transcends and relativizes freedom in the world.</p>',
    "23": '<p><strong>timēs ēgorasthēte; mē ginesthe douloi anthrōpōn</strong> (you were bought at a price; do not become slaves of people) — the same redemption-purchase formula as 6:20, now applied to social ethics: the purchased people of Christ must not trade their spiritual freedom for new social entanglements that compromise their primary allegiance. This is not a command to reject all social hierarchy but a warning against the patron-client dependencies that could compromise devotion to Christ.</p>',
    "24": '<p><strong>hekastos en hō eklēthē, adelphoi, en toutō menetō para Theō</strong> (brothers and sisters, each of you should remain before God in the situation you were in when called) — the principle restated a third time, now with the addition <em>para Theō</em> (before God / with God). The presence of God reframes the social location: whatever your condition, you are standing before God in it. Translation note flags a dispute on <em>para Theō</em>: with God (in relationship) or before God (in God\'s sight).</p>',
    "25": '<p><strong>peri de tōn parthenōn epitagēn Kyriou ouk echō, gnōmēn de didōmi</strong> (now about those who have never been married: I have no command from the Lord, but I give my judgment) — Paul is transparent about his epistemic status. <em>Parthenōn</em> (virgins, those who have never married) is the subject; he has no dominical tradition for this case. <em>Gnōmēn didōmi</em> (I give my judgment/opinion) — a weaker speech-act than <em>parangellō</em> (command) or <em>legō</em> without qualification. <em>Pistos einai hypo Kyriou</em> (to be trustworthy by the Lord\'s mercy) — his authority is mercy-given, not self-generated.</p>',
    "26": '<p><strong>enestōsan anankēn</strong> (the present crisis) — <em>anankē</em> (necessity, crisis, compulsion): scholars debate what this refers to — persecution, famine, the general eschatological urgency of the age, or a local Corinthian situation. The word elsewhere in Paul (Rom 8:35; 2 Cor 12:10) describes tribulation. <em>Enestōsan</em> (present, standing near): the crisis is already upon them. In view of this urgency, remaining in one\'s current condition is tactically wise.</p>',
    "27": '<p><strong>dedesai gynaiki; mē zētei lysin</strong> (are you committed to a wife? do not seek release) — <em>dedesai</em> (have been bound) is the perfect passive of the same verb used for legal binding. The symmetry of the verse is complete: the bound should not seek release; the free should not seek binding. Both options have equal standing; neither is commanded.</p>',
    "28": '<p><strong>thlipsin de tē sarki hexousin hoi toioutoi</strong> (those who marry will face practical hardships) — <em>thlipsis</em> (tribulation, pressure): Paul is not saying marriage is sinful but that it introduces real-world complications in a time of eschatological pressure. <em>Tē sarki</em> (in the flesh): the hardships are material and embodied, not merely spiritual. Translation note flags <em>sarx</em> here as neutral (embodied life), not the ethical sense.</p>',
    "29": '<p><strong>ho kairos synestalmenos estin</strong> (the time is contracted/compressed) — <em>synestalmenos</em> is a nautical-textile metaphor: a sail gathered in, a garment rolled up. Not merely short but pulled tight, urgent, wound up. The phrase anchors the whole of vv. 29-31: the compressed urgency of the eschatological moment means existing social structures should be worn lightly. Those with wives should live <em>hōs mē echontes</em> (as though not having them) — not abandoning them but not being absorbed by the relationship.</p>',
    "30": '<p>The fourfold <em>hōs mē</em> (as though not) series — mourning/not mourning, rejoicing/not rejoicing, buying/not owning — is Paul\'s eschatological detachment ethic. The present-age structures (grief, joy, commerce) are real but temporary. <em>Hōs mē</em> does not counsel withdrawal from these realities but a held-loosely engagement that refuses ultimate investment in them.</p>',
    "31": '<p><strong>to schēma tou kosmou toutou paragetai</strong> (the present form of this world is passing away) — <em>schēma</em> (form, fashion, outward shape): not the world itself but its present configuration. <em>Paragetai</em> (is passing away) — present tense: the transition is already underway, not merely anticipated. Paul\'s eschatology is inaugurated: the age to come has begun its incursion into the present age through Christ\'s resurrection.</p>',
    "32": '<p><strong>ho agamos merimnā ta tou Kyriou, pōs areskē tō Kyriō</strong> (the unmarried man is concerned about the things of the Lord — how to please the Lord) — <em>merimnā</em> (is anxious/concerned for): in Phil 4:6 Paul forbids anxiety; here he commends it, when it is directed toward the Lord. The point is undivided attention. <em>Areskō</em> (please): the goal of the celibate life is pleasing the Lord; the goal of the married life is also pleasing, but now divided between Lord and spouse.</p>',
    "33": '<p><strong>ho de gamēsas merimnā ta tou kosmou, pōs areskē tē gynaiki</strong> (the married man is concerned about worldly affairs — how to please his wife) — Paul does not condemn this; pleasing one\'s spouse is a legitimate and good concern. But the structural division (<em>memeristai</em>, v. 34: is divided) is real. The celibate is not morally superior but has a structural simplicity in orientation.</p>',
    "34": '<p><strong>memeristai</strong> (is divided) — perfect passive: a state of ongoing dividedness. <strong>hē agamos kai hē parthenos merimnā ta tou Kyriou</strong> (the unmarried woman or virgin is concerned about the Lord\'s things) — the symmetry with the male situation (vv. 32-33) is maintained: the unmarried woman has the same structural advantage as the unmarried man. <em>Hagia kai tō sōmati kai tō pneumati</em> (holy in body and spirit) — the celibate life is a whole-person holiness, not merely spiritual.</p>',
    "35": '<p><strong>pros to hymōn sympheron legō</strong> (I say this for your own benefit) — Paul frames his preference for celibacy as pastoral care, not imposition. <strong>ouch hina brochos hymin epibalō</strong> (not to restrict you, literally not to throw a noose on you) — the metaphor of a restraint or snare: Paul denies that he is trying to limit freedom. <strong>pros to euschēmon kai euparedron tō Kyriō aperspastōs</strong> (to promote what is fitting and to enable undivided devotion to the Lord) — <em>euparedron</em> (sitting well beside, devoted attendance): a rare term meaning devoted proximity, continuous attendance. Undivided devotion (<em>aperispastōs</em>) is the goal.</p>',
    "36": '<p><strong>ei de tis aschēmonein epi tēn parthenon autou nomizei</strong> (but if anyone thinks he is acting dishonorably toward his betrothed virgin) — the situation: a man betrothed to a virgin, constrained by the general principle of v. 26 (remain as you are), but now under social pressure that his restraint dishonors her. <em>Hyperakmos</em> (past her prime, beyond the peak of marriageable age): implies the woman is aging without marriage. Paul\'s pastoral response: if the man feels this obligation, let them marry — he does not sin.</p>',
    "37": '<p><strong>hos de hestēken en tē kardia autou hedraios</strong> (but the man who stands firm in his commitment) — <em>hedraios</em> (settled, immovable, like a foundation): the architectural metaphor of stability. Three conditions: firm in commitment (<em>hedraios</em>), under no compulsion (<em>mē echōn anankēn</em>), desire under his own authority (<em>exousian peri tou idiou thelēmatos</em>). The man who freely chooses to keep his betrothed as his betrothed does well — the choice is genuinely free and honored.</p>',
    "38": '<p><strong>hōste kai ho gamizōn tēn heautou parthenon kalōs poiei, kai ho mē gamizōn kreitton poiēsei</strong> (so the one who marries his betrothed does well, and the one who refrains from marrying does even better) — both options are <em>kalōs</em> (well); only the celibate option is <em>kreitton</em> (better). The superlative is comparative, not absolute: both are good; one has a contextual advantage. Paul will not forbid marriage; he will not pretend the advantage does not exist.</p>',
    "39": '<p><strong>gynē dedetal hō chronō ean zē ho anēr autēs</strong> (a wife is bound to her husband as long as he lives) — <em>dedetal</em> (is bound): the same binding-verb as v. 27. Death dissolves the marital bond. Translation note flags <em>nomos</em>: the law by which she is bound may be Torah-law or the general principle. <strong>monon en Kyriō</strong> (only in the Lord) — the restriction on remarriage after the husband\'s death: the new marriage must be within the community of faith.</p>',
    "40": '<p><strong>makariotēra de estin ean houtōs meinē</strong> (she will be happier if she remains as she is) — <em>makariotēra</em>: comparative of <em>makarios</em> (blessed), the beatitude-word. Paul\'s final opinion: the widow who remains unmarried is more blessed. <strong>dokō de kagō pneuma Theou echein</strong> (and I think I also have the Spirit of God) — a dry, careful claim: <em>dokō</em> (I think, I believe): not asserting certainty but claiming the same Spirit-guidance he has appealed to throughout. The modest self-defense implies someone in Corinth disputed whether Paul spoke with spiritual authority on these matters.</p>'
  },
  "8": {
    "1": '<p><strong>peri de tōn eidōlothytōn</strong> (now about food offered to idols) — the fifth Corinthian topic introduced by <em>peri de</em>. <em>Eidōlothyton</em> (idol-meat): food sacrificed to a deity in a temple context, then available for purchase in the market or served at civic/social banquets. The issue was pervasive in Greco-Roman urban life; most social occasions involved food in some way connected to temple sacrifice. <strong>gnōsis physioī, hē de agapē oikodomeī</strong> (knowledge puffs up, but love builds up) — <em>physioō</em> (puff up, inflate): Paul reuses the Corinthian-disease vocabulary from 4:6; 4:18; 5:2. <em>Agapē oikodomeī</em> (love builds up): <em>oikodomeō</em> is Paul\'s primary communal-building metaphor (1 Cor 3:9-15; 14:3-5). Translation note flags <em>agapē</em> as distinct from <em>philia</em> and <em>erōs</em>.</p>',
    "2": '<p><strong>ei tis dokei egnōkenai ti, oupō egnō kathōs dei gnōnai</strong> (anyone who thinks they know something does not yet know as they ought to know) — the two <em>gnō</em> forms contrast: <em>egnōkenai</em> (to have known: the arrogant self-assessment) and <em>egnō kathōs dei gnōnai</em> (to know as one ought to know: the standard not yet reached). Paul does not deny that knowledge is possible but reframes what it means to truly know: genuine knowledge is always accompanied by the awareness of one\'s remaining ignorance.</p>',
    "3": '<p><strong>ei de tis agapā ton Theon, houtos egnōstai hyp\' autou</strong> (but if anyone loves God, this person is known by God) — the shift from knowing to being known: the passive <em>egnōstai</em> (has been known) makes the relationship asymmetric in an important direction. It is not that the one who loves God thereby knows God better (though they may); it is that they are known by God — which is the ground of the relationship. This echoes Paul\'s argument in Gal 4:9: you have come to know God, or rather to be known by God.</p>',
    "4": '<p><strong>ouden eidōlon en kosmō</strong> (an idol has no real existence in the world) — <em>ouden</em> (nothing, no reality): the idol is nothing because there is no corresponding divine reality behind it. <strong>oudeis Theos ei mē heis</strong> (there is no God but one) — the Shema-form of Jewish monotheism (Deut 6:4) adapted: Jewish piety expressed precisely this conviction about other gods\' non-existence. The Corinthian "strong" who have this <em>gnōsis</em> are theologically correct.</p>',
    "5": '<p><strong>legoumenoi theoi</strong> (so-called gods) — Paul\'s ironic quotation marks: he does not deny the widespread social reality of polytheism (there are indeed many entities worshipped as gods and lords) but refuses them the unqualified title. <em>Eite en ouranō eite epi gēs</em> (whether in heaven or on earth) — the cosmic register of the claim: even the highest celestial powers are merely <em>legomenoi</em> (called, named) gods, not actually divine.</p>',
    "7": '<p><strong>synētheia tou eidōlou heōs arti</strong> (through their long association with idols, literally their habit of the idol until now) — <em>synētheia</em> (custom, long-established association, habit): this is not intellectual confusion but deeply embedded behavioral memory. The person\'s conscience (<em>syneidēsis</em>) has been formed by years of treating idol-meat as genuinely sacred. Even after conversion and intellectual assent to monotheism, the emotional-behavioral reflex remains. <strong>asthenēs ousa molynestai</strong> (being weak, is defiled) — the weak conscience is defiled not because the food is objectively defiling but because the person eats it with the consciousness of it as truly offered to a god.</p>',
    "8": '<p><strong>brōma de hēmas ou parastisei tō Theō</strong> (food does not bring us closer to God) — the neutral status of food: neither eating nor abstaining makes one closer to or further from God. This is the "strong" position that Paul actually affirms — the knowledge of the strong is correct. The argument that follows (vv. 9-13) does not refute the <em>gnōsis</em> but asks whether the <em>gnōsis</em> is being exercised in a way that builds or destroys.</p>',
    "9": '<p><strong>blepete de mē pōs hē exousia hymōn autē proskomma genētai tois asthenousi</strong> (but be careful that this right of yours does not become a stumbling block to the weak) — <em>exousia</em> (right, authority, freedom): the word Paul uses throughout 1 Cor 7-10 for legitimate freedom. <em>Proskomma</em> (stumbling block, obstacle): the same word as Rom 14:13 — the exercise of legitimate freedom becomes a moral obstacle for the weaker believer.</p>',
    "10": '<p><strong>oidomelēthēsetai eis to ta eidōlothyta esthiein</strong> (won\'t they be encouraged/built up to eat idol-meat?) — the irony of the verb: <em>oikodomeō</em> (build up) is Paul\'s positive term for communal edification (v. 1; 14:3), but here it denotes a destructive building — the weak believer is being built up in the direction of their destruction. Seeing the strong Christian eating in the temple precinct encourages them to participate in a way that violates their own conscience.</p>',
    "11": '<p><strong>apollytai gar ho asthenōn en tē sē gnōsei, ho adelphos di\' hon Christos apethanen</strong> (so this weak brother, for whom Christ died, is destroyed by your knowledge) — the Christological weight of the argument: the weak believer is not merely a social inconvenience but one for whom Christ died (<em>di\' hon Christos apethanen</em>). The death of Christ for the weak establishes the infinite value of the weak believer\'s conscience-integrity. Destroying that believer with food is destroying someone whom Christ valued with his life.</p>',
    "12": '<p><strong>hamartanete eis ton Christon</strong> (you are sinning against Christ) — the escalation: sinning against the weak brother\'s conscience is sinning against Christ himself. <em>Typtontes autōn tēn syneidēsin asthenousan</em> (wounding their weak conscience) — <em>typtō</em> (strike, wound): the violence of the metaphor captures the real damage done to the weak believer\'s moral integrity when they are pressured by example to violate their own conscience.</p>',
    "13": '<p><strong>dioper ei brōma skandalizei ton adelphon mou, ou mē phagō krea eis ton aiōna</strong> (therefore, if what I eat causes my brother to stumble, I will never eat meat again) — <em>skandalizō</em> (cause to stumble, trip): the foundation of Paul\'s practical conclusion. The indefinite extension (<em>eis ton aiōna</em>, forever) is rhetorical hyperbole but makes the principle absolute: Paul\'s freedom over food is entirely subordinate to the welfare of the weak believer. The argument of ch. 8 is completed in ch. 9 (Paul\'s own example of waiving rights) and ch. 10 (practical guidance on idol-meat situations).</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '1corinthians')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', '1corinthians', existing)
    for ch in ['5', '6', '7', '8']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
